  2185→### Task 5.2: Create useSession Hook
  2186→
  2187→**Files:**
  2188→- Create: `src/ui/hooks/useSession.ts`
  2189→
  2190→**Step 1: Create src/ui/hooks/useSession.ts**
  2191→
  2192→```typescript
  2193→import { useState, useEffect, useCallback } from 'react';
  2194→import type { AnyBlock, Chunk } from '@/types';
  2195→
  2196→interface WsMessage {
  2197→  type: 'blocks:update' | 'blocks:new' | 'session:init' | 'error';
  2198→  blocks?: AnyBlock[];
  2199→  chunks?: Chunk[];
  2200→}
  2201→
  2202→export function useSession() {
  2203→  const [blocks, setBlocks] = useState<AnyBlock[]>([]);
  2204→  const [chunks, setChunks] = useState<Chunk[]>([]);
  2205→  const [isConnected, setIsConnected] = useState(false);
  2206→
  2207→  useEffect(() => {
  2208→    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
  2209→    const wsUrl = `${protocol}//${window.location.host}/ws`;
  2210→
  2211→    const ws = new WebSocket(wsUrl);
  2212→
  2213→    ws.onopen = () => {
  2214→      setIsConnected(true);
  2215→      console.log('WebSocket connected');
  2216→    };
  2217→
  2218→    ws.onclose = () => {
  2219→      setIsConnected(false);
  2220→      console.log('WebSocket disconnected');
  2221→    };
  2222→
  2223→    ws.onerror = (error) => {
  2224→      console.error('WebSocket error:', error);
  2225→    };
  2226→
  2227→    ws.onmessage = (event) => {
  2228→      try {
  2229→        const message: WsMessage = JSON.parse(event.data);
  2230→
  2231→        switch (message.type) {
  2232→          case 'session:init':
  2233→          case 'blocks:update':
  2234→            if (message.blocks) {
  2235→              setBlocks(message.blocks);
  2236→            }
  2237→            if (message.chunks) {
  2238→              setChunks(message.chunks);
  2239→            }
  2240→            break;
  2241→
  2242→          case 'blocks:new':
  2243→            if (message.blocks) {
  2244→              setBlocks(prev => [...prev, ...message.blocks!]);
  2245→            }
  2246→            break;
  2247→        }
  2248→      } catch (error) {
  2249→        console.error('Failed to parse WebSocket message:', error);
  2250→      }
  2251→    };
  2252→
  2253→    return () => {
  2254→      ws.close();
  2255→    };
  2256→  }, []);
  2257→
  2258→  const scrollToBlock = useCallback((blockId: string) => {
  2259→    const element = document.getElementById(`block-${blockId}`);
  2260→    if (element) {
  2261→      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
  2262→    }
  2263→  }, []);
  2264→
  2265→  return {
  2266→    blocks,
  2267→    chunks,
  2268→    isConnected,
  2269→    scrollToBlock,
  2270→  };
  2271→}
  2272→```
