        </button>
        <button
          className="w-8 h-8 rounded flex items-center justify-center text-lg"
          style={{
            backgroundColor: theme.colors.headerBg,
            color: theme.colors.headerText,
          }}
        >
          +
        </button>
      </div>

      {/* Blocks */}
      <div className="pt-12">
